EBTYPE.file_content:
/*
  © 2021 Intel Corporation
  SPDX-License-Identifier: MPL-2.0
*/
dml 1.4;

device test;

method m() {}

method init() {
    // no error
    after 'a' s: m();
    after 'a' cycles: m();
    after cast(1,uint64_be_t) cycles: m();
    after 'a' ps: m();
    after cast(1,uint64_be_t) ps: m();
    /// ERROR EBTYPE
    after true s: m();
    /// ERROR EBTYPE
    after NULL s: m();
    /// ERROR EBTYPE
    after true cycles: m();
    /// ERROR EBTYPE
    after NULL cycles: m();
    /// ERROR EBTYPE
    after true ps: m();
    /// ERROR EBTYPE
    after NULL ps: m();

    local struct { hook() h; } str;
    // The precedence rules gives usages of "->" as binds precedence before
    // pointer subreferences
    /// ERROR EBTYPE
    after (&str)->h: m();
    // no error
    after ((&str)->h): m();
    after (&str)->h -> (): m();
}

bank b {
    register r size 4 @ unmapped_offset {
        /// ERROR EBTYPE
        field f @ [4.3:0];
    }
}

EBTYPE.hint:
The statement with error is like this:
    after true s: m();
    after NULL s: m();
    after true cycles: m();
    after NULL cycles: m();
    after true ps: m();
    after NULL ps: m();
    after (&str)->h: m();
        field f @ [4.3:0];

while the correct one should be like this:
    after 'a' s: m();
    after ((&str)->h): m();

