    hook(struct { int x; }) h1;
    hook(int (*)[nonconstant_int]) h2;
    hook(layout "little-endian" { int32 x; }) h3;
saved hook(struct { int x; }) saved_h;
    local hook(struct { int x; }) h1;
    local hook(int (*)[i]) h2;
    local hook(layout "little-endian" { int32 x; }) h3;

